import os
import sys
import boto3

def main():
    topic_arn = os.environ.get("SNS_TOPIC_ARN")
    if not topic_arn:
        topic_arn = input("Enter SNS TopicArn: ").strip()
    if not topic_arn:
        print("Missing TopicArn.", file=sys.stderr)
        sys.exit(2)

    region = os.environ.get("AWS_REGION") or os.environ.get("AWS_DEFAULT_REGION")
    sns = boto3.client("sns", region_name=region) if region else boto3.client("sns")

    print("Enter HTTPS endpoints (one per line). Blank line to finish.")
    endpoints = []
    while True:
        try:
            line = input().strip()
        except EOFError:
            break
        if not line:
            break
        endpoints.append(line)

    if not endpoints:
        print("No endpoints provided.", file=sys.stderr)
        sys.exit(2)

    results = []
    for endpoint in endpoints:
        try:
            resp = sns.subscribe(
                TopicArn=topic_arn,
                Protocol="https",
                Endpoint=endpoint
            )
            results.append((endpoint, resp.get("SubscriptionArn")))
        except Exception as e:
            results.append((endpoint, f"ERROR: {e}"))

    for endpoint, arn in results:
        print(f"{endpoint}\t{arn}")

if __name__ == "__main__":
    main()